const isObjectEmpty = (objectName) => {
  return Object.keys(objectName).length === 0
}
let changedPlaylist = []
for (const item of $input.all()) {
  if(!isObjectEmpty(item.json)){
    changedPlaylist.push({
      id:item.json.id.id,
      snapshot_id: item.json.snapshot_id
    })
  }
}


return changedPlaylist;

let data = {
  count: [0],
  spotify_totals: [0],
  playlist_ids: ['']
}

for (const input of $input.all()) {
  if (input.json.count) {
    data.count = input.json.count
  }
  if (input.json.spotify_totals) {
    data.spotify_totals = input.json.spotify_totals
  }
  if (input.json.playlist_ids) {
    data.playlist_ids = input.json.playlist_ids
  }
}

let retData = []

for (let index = 0; index < data.playlist_ids.length; index++) {
  const playlist_id = data.playlist_ids[index];
  const dbCount = data.count[index];
  const spotifyTotal = data.spotify_totals[index];
  if(dbCount !== spotifyTotal) {
    retData.push({
      id:playlist_id,
      dbCount,
      spotifyTotal,
      diff: spotifyTotal - dbCount
    })
  }
}

return retData;

const payload = []
