  const {owner, tracks, ...playlistRest} = item.json
  const {id, ...playlist} = playlistRest
  const {id: owner_id, ...ownerRest} = owner
  payload.push({owner:ownerRest, tracks,playlist, playlist_id:id, owner_id })
}

return payload;

