function slugify(str) {
  return str
    .toLowerCase()
    .trim()
    .replace(/[\s\W-]+/g, '_') // Replace spaces and non-word chars with -
    .replace(/^-+|-+$/g, '');  // Remove leading/trailing -
}

function idFromLocal(uri) {
  const onlyValue = uri.replace("spotify:local:", "");
  // const parts = onlyValue.split(":");
  // const artist = parts[0];
  // const album = parts[2];
  // const track = parts[1];
  // const duration = parts[3];
  return slugify(decodeURIComponent(onlyValue));
}

const url = $input.first().json.href;
const match = url.match(/\/playlists\/([^/]+)(?:\/|$)/);
const playlist_id = match ? match[1] : null;
