      const {
        id: origId,
        album: { id: album_id, ...restAlbum },
        ...restItem
      } = i.track;
      let id = origId;
      if (!origId) {
        // need to create a meaningful id
        id = idFromLocal(restItem.uri);
      }

      const _i = Object.assign(
        {},
        i,
        { track: restItem },
        {
          album: restAlbum,
          album_id,
          playlist_id,
          track_id: id,
        }
      );
      allItems.push(_i);
    } else {
      console.log("Missing track", item);
    }
  }
}

return allItems;

